import{_ as a,o,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"智算中心节能用能体系：从成本中心到竞争力核心","description":"","frontmatter":{},"headers":[],"relativePath":"算电协同/智算中心节能用能体系.md","filePath":"算电协同/智算中心节能用能体系.md","lastUpdated":1782213036000}'),n={name:"算电协同/智算中心节能用能体系.md"};function d(l,t,i,h,s,u){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="智算中心节能用能体系-从成本中心到竞争力核心" tabindex="-1">智算中心节能用能体系：从成本中心到竞争力核心 <a class="header-anchor" href="#智算中心节能用能体系-从成本中心到竞争力核心" aria-label="Permalink to &quot;智算中心节能用能体系：从成本中心到竞争力核心&quot;">​</a></h1><blockquote><p>AI 的尽头是能源。当一座智算中心年耗电 3-5 亿千瓦时，电费占到运营成本的 50%-70%，节能就不再是&quot;企业社会责任&quot;，而是生死存亡的竞争力问题。</p></blockquote><hr><p>2026 年 5 月 14 日，韶关联通数据中心做了一件历史上没人做过的事——它接入了广东虚拟电厂平台，根据电力现货市场的电价信号，在电价低时调增算力任务、电价高时调减算力任务，实现了&quot;算随电调&quot;。</p><p>这是国内数据中心首次以虚拟电厂形式参与电力现货交易。它证明了一件事：<strong>数据中心不仅是&quot;电老虎&quot;，还可以是电网的&quot;柔性调节器&quot;</strong>。</p><p>同一个月，国家数据局重申：国家枢纽节点新建数据中心绿电占比必须达到 80% 以上。这不是倡议，是审批红线。</p><p>三个信号同时指向一个结论——<strong>智算中心的节能用能体系，正在从&quot;可选项&quot;变成&quot;准入门槛&quot;</strong>。</p><hr><h2 id="一、现状-三个必须面对的现实" tabindex="-1">一、现状：三个必须面对的现实 <a class="header-anchor" href="#一、现状-三个必须面对的现实" aria-label="Permalink to &quot;一、现状：三个必须面对的现实&quot;">​</a></h2><h3 id="第一个现实-算力爆发-能耗指数级增长" tabindex="-1">第一个现实：算力爆发，能耗指数级增长 <a class="header-anchor" href="#第一个现实-算力爆发-能耗指数级增长" aria-label="Permalink to &quot;第一个现实：算力爆发，能耗指数级增长&quot;">​</a></h3><p>2026 年中国数据中心用电量预计达到 3000 亿千瓦时，占全社会用电量的 3.5%。单座千 P 智算中心年用电量相当于一个小型工业园。</p><p>更关键的是增速——2025-2030 年数据中心用电 CAGR 高达 15-20%。到 2030 年，这个数字可能突破 7000 亿千瓦时。届时，数据中心将成为全社会用电增长的最大单一贡献者之一。</p><h3 id="第二个现实-政策从-倡导-变成-硬约束" tabindex="-1">第二个现实：政策从&quot;倡导&quot;变成&quot;硬约束&quot; <a class="header-anchor" href="#第二个现实-政策从-倡导-变成-硬约束" aria-label="Permalink to &quot;第二个现实：政策从&quot;倡导&quot;变成&quot;硬约束&quot;&quot;">​</a></h3><p>过去几年，节能是倡议。2026 年变了：</p><ul><li><strong>PUE 红线</strong>：新建大型数据中心 PUE 必须低于 1.25，先进区域要求低于 1.2</li><li><strong>绿电硬指标</strong>：国家枢纽节点新建数据中心绿电占比 ≥80%</li><li><strong>算电协同入政府工作报告</strong>：2026 年首次写入国家级规划</li></ul><p>两条红线锁死了——绿电不够 80% 不批，PUE 不达标不建。</p><h3 id="第三个现实-电费正在吃掉利润" tabindex="-1">第三个现实：电费正在吃掉利润 <a class="header-anchor" href="#第三个现实-电费正在吃掉利润" aria-label="Permalink to &quot;第三个现实：电费正在吃掉利润&quot;">​</a></h3><p>一个千 P 智算中心年电费约 1.5-3 亿元。如果能把综合用电成本降低 20%，就是 3000-6000 万元的利润释放。这不是&quot;锦上添花&quot;，是直接决定项目 IRR 从 8% 跳到 12% 的关键杠杆。</p><hr><h2 id="二、三层架构-节能用能体系的系统设计" tabindex="-1">二、三层架构：节能用能体系的系统设计 <a class="header-anchor" href="#二、三层架构-节能用能体系的系统设计" aria-label="Permalink to &quot;二、三层架构：节能用能体系的系统设计&quot;">​</a></h2><p>节能不是一个技术点，是一个系统。我把它拆成三层。</p><h3 id="第一层-it-设备级能效——每瓦特产出最多-token" tabindex="-1">第一层：IT 设备级能效——每瓦特产出最多 Token <a class="header-anchor" href="#第一层-it-设备级能效——每瓦特产出最多-token" aria-label="Permalink to &quot;第一层：IT 设备级能效——每瓦特产出最多 Token&quot;">​</a></h3><p>这是最底层也是最直接的。核心是两件事：</p><p><strong>低功耗芯片</strong>。推理专用 ASIC 比通用 GPU 节能 5-10 倍。2026 年最值得关注的不是训练芯片，而是推理芯片——因为推理是长期、持续、海量的。</p><p><strong>液冷散热</strong>。液冷不是&quot;未来技术&quot;，已经是&quot;现在标配&quot;。冷板式液冷（PUE&lt;1.2）已经大规模商用，浸没式液冷（PUE&lt;1.05）正在快速起量。NVIDIA 从 2026 年起出货的 Rubin 系列采用 100% 全液冷方案——这意味着整个产业链都被推向了液冷。</p><p>2024 年中国液冷服务器市场规模 172.72 亿元，同比增长 67%。2025 年新建数据中心液冷渗透率已超过 50%。冷板式占 70% 市场份额，浸没式增速更快。</p><h3 id="第二层-设施级能效——pue-从-1-5-到-1-15-怎么降" tabindex="-1">第二层：设施级能效——PUE 从 1.5 到 1.15 怎么降？ <a class="header-anchor" href="#第二层-设施级能效——pue-从-1-5-到-1-15-怎么降" aria-label="Permalink to &quot;第二层：设施级能效——PUE 从 1.5 到 1.15 怎么降？&quot;">​</a></h3><p>数据中心能耗结构中，制冷占 30-40%、供电损耗占 5-10%、IT 设备占 50-60%。第二层管的就是制冷和供电。</p><p><strong>AI 制冷优化是最大被低估的机会</strong>。海外有一家公司叫 Phaidra，用 AI Agent 优化数据中心制冷系统，已经为 Google 降低了 30% 的制冷能耗。在 NVIDIA 的测试中，Phaidra 的液冷 AI Agent 将 AI 负载相关的热尖峰减少了约 80%。</p><p>国内呢？<strong>这个赛道在国内几乎是空白。</strong> 没有一家专注 AI 制冷优化的独立 SaaS 公司。</p><p><strong>储能系统&quot;一专多能&quot;</strong>。在智算中心配储能，不仅仅是备电。它在电价低时充电、高时放电，可以参与需求响应赚补贴，还能平滑新能源出力的波动。一套储能系统 = 备电 + 调峰 + 需求响应 + 绿电消纳，四个功能一个投资。</p><h3 id="第三层-系统级能效——从-被动用电-到-主动管电" tabindex="-1">第三层：系统级能效——从&quot;被动用电&quot;到&quot;主动管电&quot; <a class="header-anchor" href="#第三层-系统级能效——从-被动用电-到-主动管电" aria-label="Permalink to &quot;第三层：系统级能效——从&quot;被动用电&quot;到&quot;主动管电&quot;&quot;">​</a></h3><p>这是最上层也是最性感的——让数据中心不再是电网的被动负荷，而是主动参与者。</p><p><strong>绿电直供</strong>。通过 PPA 合同或专线，直接与新能源场站交易，度电成本可从东部工商业电价的 0.7-0.8 元降到西部的 0.2-0.3 元。乌兰察布中金数据的源网荷储一体化项目，45MW/180MWh，投产后每年自发自用绿电 8.48 亿千瓦时，替代率 38.74%。</p><p><strong>VPP 聚合+电力现货交易</strong>。这是 2026 年最令人兴奋的突破。前面说的韶关联通案例就是最好的证明——数据中心可以通过 VPP 平台参与电力现货市场，在电价低谷时多用电、高峰时少用电。这不是理论推演，是已经跑通了的商业闭环。</p><p><strong>算力调度&quot;追着电价跑&quot;</strong>。训练任务可以中断、可以迁移、可以等待。这意味着算力是可以&quot;时空转移&quot;的——把非紧急的训练任务挪到西部电价低的时候做，把推理任务留在靠近用户的地方。这个调度的经济价值巨大。</p><hr><h2 id="三、产业链-七个环节-一个被低估的价值高地" tabindex="-1">三、产业链：七个环节，一个被低估的价值高地 <a class="header-anchor" href="#三、产业链-七个环节-一个被低估的价值高地" aria-label="Permalink to &quot;三、产业链：七个环节，一个被低估的价值高地&quot;">​</a></h2><p>我把智算中心节能用能产业链拆成七个环节：</p><table tabindex="0"><thead><tr><th>环节</th><th>毛利率</th><th>资本密度</th><th>PE/VC 适合度</th></tr></thead><tbody><tr><td>AI 低功耗芯片</td><td>50-60%</td><td>极高</td><td>⭐⭐⭐</td></tr><tr><td>液冷散热系统</td><td>25-40%</td><td>中</td><td>⭐⭐⭐</td></tr><tr><td>高效供电配电</td><td>20-30%</td><td>中</td><td>⭐⭐</td></tr><tr><td>储能系统</td><td>15-25%</td><td>高</td><td>⭐⭐</td></tr><tr><td>智算中心运营</td><td>30-50%</td><td>极高</td><td>⭐⭐⭐</td></tr><tr><td><strong>能效优化服务</strong></td><td><strong>60-80%</strong></td><td><strong>极低</strong></td><td><strong>⭐⭐⭐⭐⭐</strong></td></tr><tr><td>下游算力消费</td><td>40-70%</td><td>中</td><td>⭐⭐⭐⭐</td></tr></tbody></table><p><strong>核心判断：价值最高的环节不在设备和运营，在能效优化服务。</strong></p><p>液冷散热竞争已经很激烈了——英维克、高澜、曙光数创三龙头占据大部分市场，毛利率 25-40%，这是硬件生意的正常水平。智算中心运营是重资产，一个项目砸 10 亿进去，IRR 6-10%。</p><p>能效优化服务呢？纯 SaaS，毛利率 60-80%，轻资产可复制。海外 Phaidra 的模式已验证，国内市场空白。这才是一级市场应该重仓的方向。</p><hr><h2 id="四、五种商业模式-你的钱应该放在哪里" tabindex="-1">四、五种商业模式，你的钱应该放在哪里？ <a class="header-anchor" href="#四、五种商业模式-你的钱应该放在哪里" aria-label="Permalink to &quot;四、五种商业模式，你的钱应该放在哪里？&quot;">​</a></h2><h3 id="模式-a-源网荷储一体化-重资产-适合产业资本" tabindex="-1">模式 A：源网荷储一体化（重资产，适合产业资本） <a class="header-anchor" href="#模式-a-源网荷储一体化-重资产-适合产业资本" aria-label="Permalink to &quot;模式 A：源网荷储一体化（重资产，适合产业资本）&quot;">​</a></h3><p>逻辑：自建风光+储能+数据中心 = 自平衡微电网。 IRR 6-10%，回收期 6-10 年。 适合国电投、华能这样的能源央企，不适合 PE/VC 财务投资。</p><h3 id="模式-b-分布式算力仓-绿电直供-中资产-适合有资源的玩家" tabindex="-1">模式 B：分布式算力仓+绿电直供（中资产，适合有资源的玩家） <a class="header-anchor" href="#模式-b-分布式算力仓-绿电直供-中资产-适合有资源的玩家" aria-label="Permalink to &quot;模式 B：分布式算力仓+绿电直供（中资产，适合有资源的玩家）&quot;">​</a></h3><p>在绿电富集区部署模块化算力仓，就地消纳低价绿电。 IRR 12-18%，回收期 4-6 年。 关键看 GPU 采购能力和客户获取。</p><h3 id="模式-c-能效优化-saas-轻资产-最适合-pe-vc" tabindex="-1">模式 C：能效优化 SaaS（轻资产，最适合 PE/VC） <a class="header-anchor" href="#模式-c-能效优化-saas-轻资产-最适合-pe-vc" aria-label="Permalink to &quot;模式 C：能效优化 SaaS（轻资产，最适合 PE/VC）&quot;">​</a></h3><p>AI 优化数据中心制冷/用电/交易，按节省电费分成。 毛利率 60-80%，IRR 30%+。 <strong>最大问题</strong>：国内目前没有专注这个方向的公司。要么投海外（Phaidra），要么国内孵一个。</p><h3 id="模式-d-vpp-聚合-电力交易-平台型-窗口期" tabindex="-1">模式 D：VPP 聚合+电力交易（平台型，窗口期） <a class="header-anchor" href="#模式-d-vpp-聚合-电力交易-平台型-窗口期" aria-label="Permalink to &quot;模式 D：VPP 聚合+电力交易（平台型，窗口期）&quot;">​</a></h3><p>聚合多个数据中心负荷，统一参与电力市场。 IRR 20-30%，壁垒在客户关系。 首单已落地，模式跑通，现在是规模化复制的最佳时机。</p><h3 id="模式-e-存量改造-服务型-政策驱动型" tabindex="-1">模式 E：存量改造（服务型，政策驱动型） <a class="header-anchor" href="#模式-e-存量改造-服务型-政策驱动型" aria-label="Permalink to &quot;模式 E：存量改造（服务型，政策驱动型）&quot;">​</a></h3><p>对老旧数据中心做液冷改造+能效优化。 IRR 15-25%，政策强推。 需求确定性强，但竞争门槛不高。</p><hr><h2 id="五、作为一个投资人-我怎么看" tabindex="-1">五、作为一个投资人，我怎么看？ <a class="header-anchor" href="#五、作为一个投资人-我怎么看" aria-label="Permalink to &quot;五、作为一个投资人，我怎么看？&quot;">​</a></h2><h3 id="时机判断" tabindex="-1">时机判断 <a class="header-anchor" href="#时机判断" aria-label="Permalink to &quot;时机判断&quot;">​</a></h3><p>这个赛道 2024-2025 是概念验证期，2026 年进入早期成长期。未来 12-18 个月是 PE/VC 的窗口期。</p><ul><li>液冷渗透率已超 50%——确定性最强但竞争也最激烈</li><li>VPP 聚合首单落地——模式跑通，赶紧布局</li><li>AI 制冷优化国内空白——要么第一个进去，要么等 Phaidra 进来卷</li></ul><h3 id="组合策略" tabindex="-1">组合策略 <a class="header-anchor" href="#组合策略" aria-label="Permalink to &quot;组合策略&quot;">​</a></h3><p>如果我有 1 个亿投这个赛道，我会这样分配：</p><ul><li><strong>40% 能效优化 SaaS + VPP 聚合平台</strong>（轻资产高壁垒）</li><li><strong>30% 电力交易 AI + 算力调度平台</strong>（窗口期）</li><li><strong>20% 浸没式液冷 + 分布式算力仓</strong>（前瞻布局）</li><li><strong>10% 极早期技术</strong>（光子计算等）</li></ul><h3 id="验证问题" tabindex="-1">验证问题 <a class="header-anchor" href="#验证问题" aria-label="Permalink to &quot;验证问题&quot;">​</a></h3><p>DD 时必问的五个问题：</p><ol><li><strong>收入质量</strong>：客户是试点项目还是持续付费？续约率多少？</li><li><strong>竞争壁垒</strong>：为什么电网和数据中心不自己做？</li><li><strong>数据飞轮</strong>：用的人越多，效果越好吗？</li><li><strong>政策依赖</strong>：如果电改放缓，商业模式还成立吗？</li><li><strong>团队背景</strong>：有没有既懂电力又懂 AI 的复合人才？</li></ol><hr><h2 id="六、我的判断" tabindex="-1">六、我的判断 <a class="header-anchor" href="#六、我的判断" aria-label="Permalink to &quot;六、我的判断&quot;">​</a></h2><blockquote><p><strong>第一，双 80 是硬约束不是口号。</strong> 绿电占比 80% + PUE 1.25，这两条红线决定了谁能新建智算中心。节能用能体系从&quot;加分项&quot;变成了&quot;准入门槛&quot;。</p><p><strong>第二，2026年5月广东首单是一个按钮时刻。</strong> 数据中心参与 VPP 现货交易从&quot;理论上可行&quot;变成了&quot;商业上已跑通&quot;。这个市场的规模在千亿级。</p><p><strong>第三，最性感的投资不是盖数据中心，是帮数据中心省电和赚钱。</strong> 液冷和储能是看得见的钱（30% 毛利率，重资产），能效 SaaS 和 VPP 平台是看不见的钱（60-80% 毛利率，轻资产）。一级市场应该赌后者。</p></blockquote><hr><p><em>以上为个人基于公开信息和行业研究的分析推演，不构成投资建议。</em></p><p><em>陈道雷 · 2026年6月</em></p>',72)])])}const g=a(n,[["render",d]]);export{q as __pageData,g as default};
